      entity(as[String]) { url =>
        onComplete(fetchContentFromUrl(url)) {
          case Success(content) => complete(HttpEntity(ContentTypes.`text/plain(UTF-8)`, content))
          case Failure(ex) => complete(HttpResponse(StatusCodes.InternalServerError, entity = ex.getMessage))
        }
      }
    }

  Http().bindAndHandle(route, "localhost", 8080)
